import{c as r,Q as a,j as e,m as o}from"./chunks/framework.BXc4yaFE.js";const b=JSON.parse('{"title":"COMPOSITE-STEM: Expert-Curated STEM Benchmark","description":"","frontmatter":{"url":"https://arxiv.org/abs/2604.09836","title":"COMPOSITE-STEM: Expert-Curated STEM Benchmark","date":"2026-04-10T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/inbox/low-score/2026-04-10-composite-stem-benchmark.md","filePath":"research/ai-articles/inbox/low-score/2026-04-10-composite-stem-benchmark.md","lastUpdated":1779796674000}'),n={name:"research/ai-articles/inbox/low-score/2026-04-10-composite-stem-benchmark.md"};function d(s,t,i,l,h,c){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="composite-stem-expert-curated-stem-benchmark" tabindex="-1">COMPOSITE-STEM: Expert-Curated STEM Benchmark <a class="header-anchor" href="#composite-stem-expert-curated-stem-benchmark" aria-label="Permalink to &quot;COMPOSITE-STEM: Expert-Curated STEM Benchmark&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://arxiv.org/abs/2604.09836" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.09836</a><br><strong>作者</strong>：Kyle Waters 等 23 位<br><strong>發表日期</strong>：2026-04-10<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文摘要" tabindex="-1">繁體中文摘要 <a class="header-anchor" href="#繁體中文摘要" aria-label="Permalink to &quot;繁體中文摘要&quot;">​</a></h2><h3 id="研究概述" tabindex="-1">研究概述 <a class="header-anchor" href="#研究概述" aria-label="Permalink to &quot;研究概述&quot;">​</a></h3><p>COMPOSITE-STEM 是一個包含 70 個專家撰寫任務的 Benchmark，涵蓋物理（20 題）、化學（23 題）、生物（20 題）、數學（7 題）。任務由博士級研究人員策劃，在可執行的沙箱環境中評估 AI Agent，而非靜態問答格式。</p><h3 id="評分方法" tabindex="-1">評分方法 <a class="header-anchor" href="#評分方法" aria-label="Permalink to &quot;評分方法&quot;">​</a></h3><ul><li><strong>35 題</strong>：完全比對（Exact-match grading）</li><li><strong>34 題</strong>：LLM-jury 協議（5 個前沿模型投票判斷語義正確性）</li><li><strong>1 題</strong>：混合評估</li></ul><h3 id="測試結果" tabindex="-1">測試結果 <a class="header-anchor" href="#測試結果" aria-label="Permalink to &quot;測試結果&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>準確率（Pass@1）</th></tr></thead><tbody><tr><td>Claude Opus 4.6</td><td>21.4%</td></tr><tr><td>Gemini 3.1 Pro</td><td>18.6%</td></tr><tr><td>Grok 4.20-beta</td><td>5.7%</td></tr><tr><td>GPT-5.4</td><td>4.3%</td></tr></tbody></table><p><strong>分析</strong>：表現較好的模型使用更多步驟、更頻繁使用工具、並在需要時安裝套件。</p><h3 id="執行環境" tabindex="-1">執行環境 <a class="header-anchor" href="#執行環境" aria-label="Permalink to &quot;執行環境&quot;">​</a></h3><ul><li>Python 3.12 + 標準科學套件（numpy、scipy、rdkit 等）</li><li>每題 1 小時 timeout</li><li>Harbor 框架 + Terminus-2 harness（支援多模態輸入）</li><li>容器化沙箱</li></ul><h3 id="數據集" tabindex="-1">數據集 <a class="header-anchor" href="#數據集" aria-label="Permalink to &quot;數據集&quot;">​</a></h3><p>已公開發布，供進一步研究。</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>4/10</td><td>這是一個評估工具而非設計模式；對 cc-workspace 的 harness 設計幫助有限</td></tr><tr><td>B. 創新性</td><td>6/10</td><td>LLM-jury 協議和專家策劃的科學任務有一定新穎性；但 benchmark 設計本身不算突破</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>4 個模型的量化結果、詳細的評分方法、明確的任務分類</td></tr><tr><td>D. 技術深度</td><td>6/10</td><td>Benchmark 組成和評估方法描述詳細，但執行環境設計說明有限</td></tr><tr><td>E. 泛化性</td><td>5/10</td><td>高度特化於 STEM 領域；與一般 coding agent 或 harness engineering 的關聯性弱</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.45/10</strong></td><td>4×0.3 + 6×0.2 + 7×0.2 + 6×0.15 + 5×0.15 = 1.2+1.2+1.4+0.9+0.75</td></tr></tbody></table><p><strong>整合決策</strong>：不整合（分數 ≤ 6）</p><h3 id="低分主因" tabindex="-1">低分主因 <a class="header-anchor" href="#低分主因" aria-label="Permalink to &quot;低分主因&quot;">​</a></h3><ol><li><strong>主因（A 維度低，4/10）</strong>：這是一個評估 benchmark，不包含可直接套用到 cc-workspace 的設計模式、工具或流程改善。</li><li><strong>泛化性受限（E 維度，5/10）</strong>：STEM 科學任務高度特化，與 cc-workspace 關注的 harness engineering、coding agent、context management 領域關聯性弱。</li><li><strong>對比現有資料</strong>：cc-workspace 的重心在 Agent harness 設計和優化；COMPOSITE-STEM 在評估科學推理能力，是不同的研究方向。</li></ol><h3 id="保留原因" tabindex="-1">保留原因 <a class="header-anchor" href="#保留原因" aria-label="Permalink to &quot;保留原因&quot;">​</a></h3><p>雖不建議整合，但可作為「AI 能力評估方法論」的參考資料：</p><ul><li>LLM-jury 協議（5 個模型投票）是一種可借鑒的評估設計</li><li>「最強模型僅達 21% 準確率」說明科學推理在目前仍是 Agent 的重要能力邊界</li></ul>',24)])])}const p=r(n,[["render",d]]);export{b as __pageData,p as default};
